package images

import (
	"github.com/prometheus/client_golang/prometheus"

	"github.com/sourcegraph/sourcegraph/internal/metrics"
)

var (
	imageProcessingMetrics metrics.SingletonREDMetrics

	metricImageSizeBytes = prometheus.NewHistogramVec(prometheus.HistogramOpts{
		Namespace: "src",
		Name:      "deepsearch_image_size_bytes",
		Help:      "Size of images in bytes",
		Buckets:   []float64{10_000, 50_000, 100_000, 250_000, 500_000, 1_000_000, 5_000_000},
	}, []string{"stage"}) // "input", "output"

	// metricImageEncoding tracks image format conversions during processing.
	// Example queries:
	//   sum(src_deepsearch_image_encoding_total{input_format="png"}) - total PNG inputs
	//   sum(src_deepsearch_image_encoding_total{output_format="jpeg"}) - total JPEG outputs
	//   src_deepsearch_image_encoding_total{input_format="png",output_format="jpeg"} - PNG to JPEG conversions
	metricImageEncoding = prometheus.NewCounterVec(prometheus.CounterOpts{
		Namespace: "src",
		Name:      "deepsearch_image_encoding_total",
		Help:      "Count of image encoding operations by input and output format",
	}, []string{"input_format", "output_format"})
)

func init() {
	prometheus.MustRegister(metricImageSizeBytes)
	prometheus.MustRegister(metricImageEncoding)
}

func getImageProcessingMetrics() *metrics.REDMetrics {
	return imageProcessingMetrics.Get(func() *metrics.REDMetrics {
		return metrics.NewREDMetrics(
			prometheus.DefaultRegisterer,
			"deepsearch_image_processing",
			metrics.WithLabels("operation"),
			metrics.WithDurationBuckets([]float64{0.01, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5}),
		)
	})
}

