package images

import (
	"encoding/base64"
	"strings"

	goapi "github.com/sourcegraph/sourcegraph/internal/openapi/goapi"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

// Keep in sync with client/web-sveltekit/src/routes/(app)/deepsearch/image-utils.ts
const (
	MaxImagesPerMessage = 2
	MaxImageSize        = 5 * 1024 * 1024 // 5 MB - Anthropic API limit
)

var AllowedImageMimeTypes = map[string]bool{
	"image/jpeg": true,
	"image/png":  true,
	"image/webp": true,
}

func ValidateImageBlocks(content goapi.ContentBlocks) error {
	if content == nil {
		return nil
	}

	imageCount := 0

	for _, block := range content {
		img, ok := block.(*goapi.ImageContent)
		if !ok {
			continue
		}
		imageCount++

		if imageCount > MaxImagesPerMessage {
			return errors.Newf("maximum %d images allowed per message", MaxImagesPerMessage)
		}

		if err := validateImageContent(img); err != nil {
			return err
		}
	}

	return nil
}

func validateImageContent(img *goapi.ImageContent) error {
	if img.Url == "" {
		return errors.New("image url is required")
	}

	if !strings.HasPrefix(img.Url, "data:") {
		return errors.New("image url must be data URI")
	}

	mimeType, data, err := parseDataURI(img.Url)
	if err != nil {
		return err
	}

	if !AllowedImageMimeTypes[mimeType] {
		return errors.Newf("unsupported image type %q", mimeType)
	}

	if len(data) > MaxImageSize {
		return errors.Newf("image too large: %d bytes exceeds maximum of %d bytes", len(data), MaxImageSize)
	}

	return nil
}

// parseDataURI extracts the MIME type and decoded binary data from a data URI.
//
// Expected format: data:<mediatype>;base64,<data>
// Example: data:image/png;base64,iVBORw0KGgo...
//
// Returns an error if:
//   - The URI doesn't contain a comma separator
//   - The URI is not base64 encoded (missing ";base64" before comma)
//   - The base64 data is malformed
func parseDataURI(dataURI string) (mimeType string, data []byte, err error) {
	withoutPrefix := strings.TrimPrefix(dataURI, "data:")
	before, after, ok := strings.Cut(withoutPrefix, ",")
	if !ok {
		return "", nil, errors.New("invalid data URI: missing comma separator")
	}

	header := before
	encodedData := after

	headerParts := strings.Split(header, ";")
	if len(headerParts) < 2 || headerParts[len(headerParts)-1] != "base64" {
		return "", nil, errors.New("invalid data URI: must be base64 encoded")
	}

	mimeType = headerParts[0]

	data, err = base64.StdEncoding.DecodeString(encodedData)
	if err != nil {
		return "", nil, errors.Wrap(err, "invalid base64 data in image URI")
	}

	return mimeType, data, nil
}

