cat > /workspace/cmd/frontend/internal/deepsearchapi/images/processing.go << 'GOEOF'
package images

import (
	"bytes"
	"encoding/base64"
	"fmt"
	"image"
	"image/jpeg"
	"image/png"
	"math"
	"time"

	"github.com/anthonynsimon/bild/transform"
	_ "golang.org/x/image/webp" // register webp decoder for image.Decode

	"github.com/sourcegraph/sourcegraph/internal/openapi/goapi"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

// Based on Anthropic's recommendations:
//   - Images over 1568px trigger server-side resize, adding latency
//   - Over 1.15MP degrades time-to-first-token
//
// Gemini tiles images into 768x768 chunks; staying under 1568px limits tiling to ~6 tiles.
//
// Ref: https://platform.claude.com/docs/en/build-with-claude/vision#evaluate-image-size
//
// Ref: https://ai.google.dev/gemini-api/docs/image-understanding
const (
	MaxImageDimension = 1568
	MaxMegaPixels     = 1.15
	MaxCompressedSize = 500 * 1024 // 500KB - target size for DB storage

	// MaxDecodablePixels is the maximum number of pixels we allow before
	// decoding an image. This prevents decompression bombs where a small
	// compressed image expands to gigabytes in memory.
	// 25MP × 4 bytes/pixel ≈ 100MB max memory for the decoded image.
	MaxDecodablePixels = 25_000_000

	// pngSizeThreshold is the pixel count above which we skip PNG encoding.
	// Large images won't compress to under MaxCompressedSize as PNG anyway.
	pngSizeThreshold = 1000 * 1000
)

// JPEG quality levels to try until output is under MaxCompressedSize.
var jpegQualities = []int{80, 50, 30}

// CountImages returns the number of image blocks in the content.
func CountImages(content goapi.ContentBlocks) int32 {
	var count int32
	for _, block := range content {
		if _, ok := block.(*goapi.ImageContent); ok {
			count++
		}
	}
	return count
}

// Downscales an image if it exceeds size limits.
func ProcessImageBlocks(content goapi.ContentBlocks) error {
	for _, block := range content {
		img, ok := block.(*goapi.ImageContent)
		if !ok {
			continue
		}
		if err := processImageContent(img); err != nil {
			return err
		}
	}
	return nil
}

func processImageContent(img *goapi.ImageContent) error {
	mimeType, data, err := parseDataURI(img.Url)
	if err != nil {
		return err
	}

	processedData, outputMimeType, err := processImageData(data, mimeType)
	if err != nil {
		return err
	}

	// Rebuild the data URI
	encoded := base64.StdEncoding.EncodeToString(processedData)
	img.Url = fmt.Sprintf("data:%s;base64,%s", outputMimeType, encoded)

	return nil
}

func processImageData(data []byte, mediaType string) (result []byte, outputType string, err error) {
	start := time.Now()
	metricImageSizeBytes.WithLabelValues("input").Observe(float64(len(data)))
	defer func() { getImageProcessingMetrics().Observe(time.Since(start).Seconds(), 1, &err, "process") }()

	reader := bytes.NewReader(data)

	cfg, format, err := image.DecodeConfig(reader)
	if err != nil {
		return nil, "", errors.Wrap(err, "failed to read image config")
	}
	if cfg.Width*cfg.Height > MaxDecodablePixels {
		return nil, "", errors.Newf("image dimensions too large: %dx%d (%d pixels) exceeds maximum of %d pixels",
			cfg.Width, cfg.Height, cfg.Width*cfg.Height, MaxDecodablePixels)
	}

	reader.Reset(data)
	decoded, _, err := image.Decode(reader)
	if err != nil {
		return nil, "", errors.Wrap(err, "failed to decode img")
	}

	bounds := decoded.Bounds()
	width, height := bounds.Dx(), bounds.Dy()

	longest := max(width, height)
	totalPixels := width * height
	maxPixels := int(MaxMegaPixels * 1_000_000)

	needsResize := longest > MaxImageDimension || totalPixels > maxPixels
	needsCompress := len(data) > MaxCompressedSize
	if !needsResize && !needsCompress {
		metricImageSizeBytes.WithLabelValues("output").Observe(float64(len(data)))
		return data, mediaType, nil
	}

	if needsResize {
		// Fit within MaxImageDimension while preserving aspect ratio
		decoded = fitImage(decoded, MaxImageDimension, MaxImageDimension)

		// Further scale if still over megapixel limit
		bounds := decoded.Bounds()
		if bounds.Dx()*bounds.Dy() > maxPixels {
			scale := math.Sqrt(float64(maxPixels) / float64(bounds.Dx()*bounds.Dy()))
			newWidth := int(float64(bounds.Dx()) * scale)
			newHeight := int(float64(bounds.Dy()) * scale)
			decoded = transform.Resize(decoded, newWidth, newHeight, transform.MitchellNetravali)
		}
	}

	result, outputType, err = encodeWithSizeLimit(decoded, format)
	if err != nil {
		return nil, "", err
	}
	metricImageSizeBytes.WithLabelValues("output").Observe(float64(len(result)))

	return result, outputType, nil
}

// fitImage resizes an image to fit within maxWidth x maxHeight while preserving aspect ratio.
// If the image already fits, it is returned unchanged.
func fitImage(img image.Image, maxWidth, maxHeight int) image.Image {
	bounds := img.Bounds()
	width, height := bounds.Dx(), bounds.Dy()

	if width <= maxWidth && height <= maxHeight {
		return img
	}

	// Calculate scale factor to fit within bounds
	scaleW := float64(maxWidth) / float64(width)
	scaleH := float64(maxHeight) / float64(height)
	scale := math.Min(scaleW, scaleH)

	newWidth := int(float64(width) * scale)
	newHeight := int(float64(height) * scale)

	return transform.Resize(img, newWidth, newHeight, transform.MitchellNetravali)
}

// encodeWithSizeLimit encodes an image, reducing JPEG quality until under MaxCompressedSize.
// PNGs that exceed the limit are converted to JPEG.
func encodeWithSizeLimit(img image.Image, format string) ([]byte, string, error) {
	bounds := img.Bounds()
	pixels := bounds.Dx() * bounds.Dy()

	isPNG := format == "png"

	// Only try PNG for small images - large PNGs won't fit under MaxCompressedSize
	if isPNG && pixels <= pngSizeThreshold {
		var buf bytes.Buffer
		if err := png.Encode(&buf, img); err != nil {
			return nil, "", errors.Wrap(err, "failed to encode PNG")
		}
		if buf.Len() <= MaxCompressedSize {
			metricImageEncoding.WithLabelValues(format, "png").Inc()
			return buf.Bytes(), "image/png", nil
		}
	}

	// Encode as JPEG, reducing quality until under size limit
	var buf bytes.Buffer
	for _, quality := range jpegQualities {
		buf.Reset()
		if err := jpeg.Encode(&buf, img, &jpeg.Options{Quality: quality}); err != nil {
			return nil, "", errors.Wrap(err, "failed to encode JPEG")
		}
		if buf.Len() <= MaxCompressedSize {
			metricImageEncoding.WithLabelValues(format, "jpeg").Inc()
			return buf.Bytes(), "image/jpeg", nil
		}
	}
	return nil, "", errors.Newf("image too large: %d bytes after compression (max %d)", buf.Len(), MaxCompressedSize)
}
GOEOF

