package images

import (
	"bytes"
	"image"
	"image/color"
	"image/png"
	"testing"
	"time"

	"github.com/sourcegraph/sourcegraph/lib/check"
)

// createTestImage generates a gradient PNG image of the specified dimensions.
func createTestImage(tb testing.TB, width, height int) []byte {
	tb.Helper()
	img := image.NewRGBA(image.Rect(0, 0, width, height))
	for y := range height {
		for x := range width {
			// Smooth gradient - compresses well in PNG
			r := uint8((x * 255) / width)
			g := uint8((y * 255) / height)
			img.Set(x, y, color.RGBA{R: r, G: g, B: 128, A: 255})
		}
	}
	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		tb.Fatalf("failed to create test image: %v", err)
	}
	return buf.Bytes()
}

// createNoisyTestImage generates a pseudo-random noisy PNG image. Warning: These
// can get compute-heavy and take some time to compress.
func createNoisyTestImage(tb testing.TB, width, height int) []byte {
	tb.Helper()
	img := image.NewRGBA(image.Rect(0, 0, width, height))
	seed := uint32(12345)
	for y := range height {
		for x := range width {
			seed = seed*1103515245 + 12345
			r := uint8(seed >> 16)
			seed = seed*1103515245 + 12345
			g := uint8(seed >> 16)
			seed = seed*1103515245 + 12345
			bl := uint8(seed >> 16)
			img.Set(x, y, color.RGBA{R: r, G: g, B: bl, A: 255})
		}
	}
	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		tb.Fatalf("failed to create test image: %v", err)
	}
	return buf.Bytes()
}

func TestProcessImageData_NoProcessingNeeded(t *testing.T) {
	// Small image within all limits
	data := createTestImage(t, 100, 100)

	result, mimeType, err := processImageData(data, "image/png")
	check.NoError(t, err)
	check.MustEqual(t, "image/png", mimeType)
	check.MustEqual(t, string(data), string(result)) // Should return original data unchanged
}

func TestProcessImageData_ResizeDimension(t *testing.T) {
	// Image exceeds max dimension (1568px)
	data := createTestImage(t, 2000, 1000)

	result, _, err := processImageData(data, "image/png")
	check.NoError(t, err)

	// Decode result to check dimensions
	decoded, _, err := image.Decode(bytes.NewReader(result))
	check.NoError(t, err)

	bounds := decoded.Bounds()
	if bounds.Dx() > MaxImageDimension || bounds.Dy() > MaxImageDimension {
		t.Errorf("image not resized: got %dx%d, max dimension is %d", bounds.Dx(), bounds.Dy(), MaxImageDimension)
	}
	// Verify aspect ratio preserved (2:1)
	ratio := float64(bounds.Dx()) / float64(bounds.Dy())
	if ratio < 1.9 || ratio > 2.1 {
		t.Errorf("aspect ratio not preserved: got %f, expected ~2.0", ratio)
	}
}

func TestProcessImageData_ResizeMegapixels(t *testing.T) {
	// Image within dimension limit but exceeds megapixel limit
	// 1500x1500 = 2.25MP > 1.15MP limit
	data := createTestImage(t, 1500, 1500)

	result, _, err := processImageData(data, "image/png")
	check.NoError(t, err)

	decoded, _, err := image.Decode(bytes.NewReader(result))
	check.NoError(t, err)

	bounds := decoded.Bounds()
	pixels := bounds.Dx() * bounds.Dy()
	maxPixels := int(MaxMegaPixels * 1_000_000)

	if pixels > maxPixels {
		t.Errorf("image not resized for megapixels: got %d pixels, max is %d", pixels, maxPixels)
	}
}

func TestProcessImageData_CompressOnly(t *testing.T) {
	// Create a larger image that will exceed MaxCompressedSize when encoded
	// but is within dimension/megapixel limits
	data := createTestImage(t, 800, 800)

	// Only runs compression path if len(data) > MaxCompressedSize
	// This test verifies the function handles the compress-only case
	_, mimeType, err := processImageData(data, "image/png")
	check.NoError(t, err)
	// Should stay PNG if under size limit, or become JPEG if over
	if mimeType != "image/png" && mimeType != "image/jpeg" {
		t.Errorf("unexpected mime type: %s", mimeType)
	}
}

func TestEncodeWithSizeLimit_PNGUnderLimit(t *testing.T) {
	img := image.NewRGBA(image.Rect(0, 0, 100, 100))

	result, mimeType, err := encodeWithSizeLimit(img, "png")
	check.NoError(t, err)
	check.MustEqual(t, "image/png", mimeType)

	if len(result) > MaxCompressedSize {
		t.Errorf("result exceeds size limit: %d > %d", len(result), MaxCompressedSize)
	}
}

