	tb.Helper()
	img := image.NewRGBA(image.Rect(0, 0, width, height))
	seed := uint32(12345)
	for y := range height {
		for x := range width {
			seed = seed*1103515245 + 12345
			r := uint8(seed >> 16)
			seed = seed*1103515245 + 12345
			g := uint8(seed >> 16)
			seed = seed*1103515245 + 12345
