19: // overall system is in a healthy or unhealthy state. In particular, rate
20: // only measures goodput, not latency.
21: //
22: // For example, if the rate is high, errors are low, and duration is low,
23: // it's still possible that the system is in a unhealthy state if there
24: // is a queue that is always ~full (and hence latency can be high).
25: //
26: // See also: https://thenewstack.io/monitoring-microservices-red-method/
27: // as well as USE metrics: https://thenewstack.io/monitoring-methodologies-red-and-use/
28: type REDMetrics struct {
29: 	Count    *prometheus.CounterVec   // How many things were processed?
30: 	Errors   *prometheus.CounterVec   // How many errors occurred?
31: 	Duration *prometheus.HistogramVec // How long did it take?
32: }
33: 
34: // Observe registers an observation of a single operation.
35: func (m *REDMetrics) Observe(secs, count float64, err *error, lvals ...string) {
36: 	if m == nil {
37: 		return
38: 	}
39: 
40: 	if err != nil && *err != nil {
41: 		if !errors.HasType[errors.ClientError](*err) {
42: 			m.Errors.WithLabelValues(lvals...).Inc()
43: 		}
44: 		m.Count.WithLabelValues(lvals...).Add(0)
45: 	} else {
46: 		m.Duration.WithLabelValues(lvals...).Observe(secs)
47: 		m.Count.WithLabelValues(lvals...).Add(count)
48: 	}
49: }
50: 
51: type redMetricOptions struct {
52: 	subsystem       string
53: 	durationHelp    string
54: 	countHelp       string
55: 	errorsHelp      string
56: 	labels          []string
57: 	durationBuckets []float64
58: }
59: 
60: // REDMetricsOption alter the default behavior of NewREDMetrics.
61: type REDMetricsOption func(o *redMetricOptions)
62: 
63: // WithDurationBuckets overrides the default histogram bucket values for duration metrics.
64: func WithDurationBuckets(buckets []float64) REDMetricsOption {
65: 	return func(o *redMetricOptions) {
66: 		if len(buckets) != 0 {
67: 			o.durationBuckets = buckets
68: 		}
69: 	}
70: }
71: 
72: // WithCountHelp overrides the default help text for count metrics.
73: func WithCountHelp(text string) REDMetricsOption {
74: 	return func(o *redMetricOptions) { o.countHelp = text }
75: }
76: 
77: // WithErrorsHelp overrides the default help text for errors metrics.
78: func WithErrorsHelp(text string) REDMetricsOption {
79: 	return func(o *redMetricOptions) { o.errorsHelp = text }
80: }
81: 
82: // WithLabels overrides the default labels for all metrics.
83: func WithLabels(labels ...string) REDMetricsOption {
84: 	return func(o *redMetricOptions) { o.labels = labels }
85: }
86: 
87: // NewREDMetrics creates an REDMetrics value. The metrics will be
88: // immediately registered to the given registerer. This method panics on registration
89: // error. The supplied metricPrefix should be underscore_cased as it is used in the
90: // metric name.
91: func NewREDMetrics(r prometheus.Registerer, metricPrefix string, fns ...REDMetricsOption) *REDMetrics {
92: 	options := &redMetricOptions{
93: 		durationHelp:    fmt.Sprintf("Time in seconds spent performing successful %s operations", metricPrefix),
94: 		countHelp:       fmt.Sprintf("Total number of successful %s operations", metricPrefix),
95: 		errorsHelp:      fmt.Sprintf("Total number of %s operations resulting in an unexpected error", metricPrefix),
96: 		labels:          nil,
97: 		durationBuckets: prometheus.DefBuckets,
98: 	}
99: 
100: 	for _, fn := range fns {
101: 		fn(options)
102: 	}
103: 
104: 	duration := prometheus.NewHistogramVec(
105: 		prometheus.HistogramOpts{
106: 			Namespace: "src",
107: 			Name:      fmt.Sprintf("%s_duration_seconds", metricPrefix),
108: 			Help:      options.durationHelp,
109: 			Buckets:   options.durationBuckets,
110: 		},
111: 		options.labels,
112: 	)
113: 	duration = MustRegisterIgnoreDuplicate(r, duration)
114: 
115: 	count := prometheus.NewCounterVec(
116: 		prometheus.CounterOpts{
117: 			Namespace: "src",
118: 			Name:      fmt.Sprintf("%s_total", metricPrefix),
119: 			Help:      options.countHelp,
120: 		},
121: 		options.labels,
122: 	)
123: 	count = MustRegisterIgnoreDuplicate(r, count)
124: 
125: 	errors := prometheus.NewCounterVec(
126: 		prometheus.CounterOpts{
127: 			Namespace: "src",
128: 			Name:      fmt.Sprintf("%s_errors_total", metricPrefix),
129: 			Help:      options.errorsHelp,
130: 		},
131: 		options.labels,
132: 	)
133: 	errors = MustRegisterIgnoreDuplicate(r, errors)
134: 
135: 	return &REDMetrics{
136: 		Duration: duration,
137: 		Count:    count,
138: 		Errors:   errors,
139: 	}
140: }
141: 
142: // MustRegisterIgnoreDuplicate is like registerer.MustRegister(collector), except that it returns
143: // the already registered collector with the same ID if a duplicate collector is attempted to be
144: // registered.
145: func MustRegisterIgnoreDuplicate[T prometheus.Collector](registerer prometheus.Registerer, collector T) T {
146: 	if err := registerer.Register(collector); err != nil {
147: 		if e, ok := err.(prometheus.AlreadyRegisteredError); ok {
148: 			return e.ExistingCollector.(T)
149: 		}
150: 		panic(err) // otherwise, panic (as registerer.MustRegister would)
151: 	}
152: 	return collector
153: }
154: 
155: type SingletonREDMetrics struct {
156: 	once    sync.Once
157: 	metrics *REDMetrics
158: }
159: 
160: // Get returns a RED metrics instance. If no instance has been
161: // created yet, one is constructed with the given create function. This method is safe to
162: // access concurrently.
163: func (m *SingletonREDMetrics) Get(create func() *REDMetrics) *REDMetrics {
164: 	m.once.Do(func() {
165: 		m.metrics = create()
166: 	})
167: 	return m.metrics
168: }
169: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/internal/metrics/operation.go"}

{"content":"1: package goapi
2: 
3: import (
4: 	"encoding/json"
5: 
6: 	"github.com/sourcegraph/sourcegraph/lib/errors"
7: )
8: 
9: // ContentBlock is a union type for all content block types.
10: // Discriminated by the "type" field.
11: type ContentBlock interface {
12: 	isContentBlock()
13: }
14: 
15: func (*SourceReferenceContent) isContentBlock() {}
16: func (*ImageContent) isContentBlock()           {}
17: func (*SlackThreadContent) isContentBlock()     {}
18: func (*ForkOrigin) isContentBlock()             {}
19: 
20: type SourceReferenceContent struct {
21: 	Type      string `json:"type"`
22: 	Repo      string `json:"repo"`
23: 	Path      string `json:"path,omitempty"`
24: 	Rev       string `json:"rev,omitempty"`
25: 	LineStart int32  `json:"line_start,omitempty"`
26: 	LineEnd   int32  `json:"line_end,omitempty"`
27: 	Source    string `json:"source,omitempty"`
28: }
29: 
30: // ImageContent represents an image content block for DeepSearch.
31: // The Url field should contain a data URI (e.g., "data:image/png;base64,...").
32: type ImageContent struct {
33: 	Type string `json:"type"`
34: 	Url  string `json:"url"`
35: }
36: 
37: // SlackThreadContent represents Slack thread context for DeepSearch.
38: // Used when a DeepSearch question originates from a Slack thread reply.
39: type SlackThreadContent struct {
40: 	Type    string `json:"type"`
41: 	Content string `json:"content"`
42: }
43: 
44: // ForkOrigin represents a reference to a previous DeepSearch conversation.
45: // Used for forking from a specific question.
46: type ForkOrigin struct {
47: 	Type       string  `json:"type"`
48: 	QuestionID int32   `json:"question_id"`
49: 	Content    *string `json:"content,omitempty"`
50: }
51: 
52: // ContentBlocks is a slice of ContentBlock used for JSON marshaling/unmarshaling
53: // of the discriminated union. Use @gotype("ContentBlocks") in TypeSpec.
54: type ContentBlocks []ContentBlock
55: 
56: func (c *ContentBlocks) UnmarshalJSON(data []byte) error {
57: 	if len(data) == 0 || string(data) == "null" {
58: 		*c = nil
59: 		return nil
60: 	}
61: 
62: 	var rawBlocks []json.RawMessage
63: 	if err := json.Unmarshal(data, &rawBlocks); err != nil {
64: 		return err
65: 	}
66: 
67: 	result := make(ContentBlocks, 0, len(rawBlocks))
68: 	for _, raw := range rawBlocks {
69: 		// Peek at the "type" field to determine which concrete type to unmarshal into.
70: 		var discriminator struct {
71: 			Type string `json:"type"`
72: 		}
73: 		if err := json.Unmarshal(raw, &discriminator); err != nil {
74: 			return err
75: 		}
76: 
77: 		var block ContentBlock
78: 		switch discriminator.Type {
79: 		case "source_reference":
80: 			var v SourceReferenceContent
81: 			if err := json.Unmarshal(raw, &v); err != nil {
82: 				return err
83: 			}
84: 			block = &v
85: 		case "image":
86: 			var v ImageContent
87: 			if err := json.Unmarshal(raw, &v); err != nil {
88: 				return err
89: 			}
90: 			block = &v
91: 		case "slack_thread":
92: 			var v SlackThreadContent
93: 			if err := json.Unmarshal(raw, &v); err != nil {
94: 				return err
95: 			}
96: 			block = &v
97: 		case "fork_origin":
98: 			var v ForkOrigin
99: 			if err := json.Unmarshal(raw, &v); err != nil {
100: 				return err
101: 			}
102: 			block = &v
103: 		default:
104: 			return errors.Newf("unknown content block type: %q", discriminator.Type)
105: 		}
106: 		result = append(result, block)
107: 	}
108: 
109: 	*c = result
110: 	return nil
111: }
112: 
113: func (c *ContentBlocks) MarshalJSON() ([]byte, error) {
114: 	if c == nil || *c == nil {
115: 		return []byte("null"), nil
116: 	}
117: 	return json.Marshal([]ContentBlock(*c))
118: }
