{"content":"1: package errors
2: 
3: import (
4: 	"context"
5: )
6: 
7: // Ignore filters out any errors that match pred. This applies
8: // recursively to MultiErrors, filtering out any child errors
9: // that match `pred`, or returning `nil` if all of the child
10: // errors match `pred`.
11: func Ignore(err error, pred ErrorPredicate) error {
12: 	// If the error (or any wrapped error) is a multierror,
13: 	// filter its children.
14: 	var multi *multiError
15: 	if As(err, &multi) {
16: 		filtered := multi.errs[:0]
17: 		for _, childErr := range multi.errs {
18: 			if ignored := Ignore(childErr, pred); ignored != nil {
19: 				filtered = append(filtered, ignored)
20: 			}
21: 		}
22: 		if len(filtered) == 0 {
23: 			return nil
24: 		}
25: 		multi.errs = filtered
26: 		return err
27: 	}
28: 
29: 	if pred(err) {
30: 		return nil
31: 	}
32: 	return err
33: }
34: 
35: // ErrorPredicate is a function type that returns whether an error matches a given condition
36: type ErrorPredicate func(error) bool
37: 
38: // IsPred returns an ErrorPredicate that returns true for errors that uwrap to the target error
39: func IsPred(target error) ErrorPredicate {
40: 	return func(err error) bool {
41: 		return Is(err, target)
42: 	}
43: }
44: 
45: func IsContextCanceled(err error) bool {
46: 	return Is(err, context.Canceled)
47: }
48: 
49: func IsDeadlineExceeded(err error) bool {
50: 	return Is(err, context.DeadlineExceeded)
51: }
