{"content":"1: package errors
2: 
3: import (
4: 	"fmt"
5: 
6: 	"github.com/cockroachdb/errors" //nolint:depguard // needed for implementation of multiError.As
7: )
8: 
9: // MultiError is a container for groups of errors.
10: type MultiError interface {
11: 	error
12: 	// Errors returns all errors carried by this MultiError, or an empty slice otherwise.
13: 	Errors() []error
14: }
15: 
16: // multiError is our default underlying implementation for MultiError. It is compatible
17: // with cockroachdb.Error's formatting, printing, etc. and supports introspecting via
18: // As, Is, and friends.
19: //
20: // Implementation is based on https://github.com/knz/shakespeare/blob/master/pkg/cmd/errors.go
21: type multiError struct {
22: 	errs []error
23: }
24: 
25: var _ MultiError = (*multiError)(nil)
26: var _ Typed = (*multiError)(nil)
27: 
28: func combineNonNilErrors(err1 error, err2 error) MultiError {
29: 	multi1, ok1 := err1.(MultiError)
30: 	multi2, ok2 := err2.(MultiError)
31: 	// flatten
32: 	var errs []error
33: 	if ok1 && ok2 {
34: 		errs = append(multi1.Errors(), multi2.Errors()...)
35: 	} else if ok1 {
36: 		errs = append(multi1.Errors(), err2)
37: 	} else if ok2 {
38: 		errs = append([]error{err1}, multi2.Errors()...)
39: 	} else {
40: 		errs = []error{err1, err2}
41: 	}
42: 	return &multiError{errs: errs}
43: }
44: 
45: // CombineErrors returns a MultiError from err1 and err2. If both are nil, nil is returned.
46: func CombineErrors(err1, err2 error) MultiError {
47: 	if err1 == nil && err2 == nil {
48: 		return nil
49: 	}
50: 	if err1 == nil {
51: 		if multi, ok := err2.(MultiError); ok {
52: 			return multi
53: 		}
54: 		return &multiError{errs: []error{err2}}
55: 	} else if err2 == nil {
56: 		if multi, ok := err1.(MultiError); ok {
57: 			return multi
58: 		}
59: 		return &multiError{errs: []error{err1}}
60: 	}
61: 	return combineNonNilErrors(err1, err2)
62: }
63: 
64: // Append returns a MultiError created from all given errors, skipping errs that are nil.
65: // If no non-nil errors are provided, nil is returned.
66: func Append(err error, errs ...error) MultiError {
67: 	multi := CombineErrors(err, nil)
68: 	for _, e := range errs {
69: 		if e != nil {
70: 			multi = CombineErrors(multi, e)
71: 		}
72: 	}
73: 	return multi
74: }
75: 
76: func (e *multiError) Error() string { return fmt.Sprintf("%v", e) }
77: func (e *multiError) Errors() []error {
78: 	if e == nil || e.errs == nil {
79: 		return nil
80: 	}
81: 	return e.errs
82: }
83: 
84: func (e *multiError) Cause() error  { return e.errs[len(e.errs)-1] }
85: func (e *multiError) Unwrap() error { return e.errs[len(e.errs)-1] }
86: 
87: func (e *multiError) Is(refError error) bool {
88: 	if e == refError {
89: 		return true
90: 	}
91: 	for _, err := range e.errs {
92: 		if Is(err, refError) {
93: 			return true
94: 		}
95: 	}
96: 	return false
97: }
98: 
99: func (e *multiError) As(target any) bool {
100: 	if m, ok := target.(*multiError); ok {
101: 		*m = *e
102: 		return true
103: 	}
104: 	for _, err := range e.errs {
105: 		// To conform to the Typed interface, 'target' has to be of type
106: 		// any. This means we cannot use our custom As wrapper which has
107: 		// a generic argument, so use cockroachdb's As instead.
108: 		if errors.As(err, target) {
109: 			return true
110: 		}
111: 	}
112: 	return false
113: }
