{"content":"1: package errors
2: 
3: import (
4: 	"reflect"
5: 	"slices"
6: 	"sync"
7: 
8: 	"go.opentelemetry.io/otel/attribute"
9: )
10: 
11: type RichError interface {
12: 	// Unpack extracts the underlying error and attributes from a RichError.
13: 	//
14: 	// Unpacking should only return attributes one-level deep; a caller may
15: 	// optionally continue recursively unpacking the underlying error.
16: 	Unpack() RichErrorData
17: }
18: 
19: type RichErrorData struct {
20: 	Err   error
21: 	Attrs []attribute.KeyValue
22: }
23: 
24: type PtrRichError[A any] interface {
25: 	*A
26: 	RichError
27: }
28: 
29: // NewRichError is a helper function for wrapping custom errors
30: // for the observation package.
31: //
32: // Pre-condition: The outermost level of ptr must be non-nil.
33: //
34: // Generally, this is easy to satisfy by using & on a named return value.
35: //
36: // The type signature is more complicated than usual to avoid an extra
37: // level of pointer indirection when the type implementing RichError uses
38: // a pointer receiver for RichError.Unpack. See rich_error_test.go for
39: // examples.
40: func NewRichError[A any, T PtrRichError[A]](ptr2 **A) *RichError {
41: 	v := RichError(NewErrorPtr[A, T](ptr2))
42: 	return &v
43: }
44: 
45: func UnpackRichErrorPtr(richErr *RichError) (error, []attribute.KeyValue) {
46: 	if richErr == nil || *richErr == nil {
47: 		return nil, nil
48: 	}
49: 	if val := reflect.ValueOf(*richErr); val.Kind() == reflect.Pointer && val.IsNil() {
50: 		return nil, nil
51: 	}
52: 	data := (*richErr).Unpack()
53: 	return data.Err, data.Attrs
54: }
55: 
56: type ErrorPtr[A any, T PtrRichError[A]] struct {
57: 	ptr2 **A
58: }
59: 
60: // nolint:unused
61: func typeAssertion[A any, T PtrRichError[A]]() {
62: 	var _ RichError = (*ErrorPtr[A, T])(nil)
63: }
64: 
65: // NewErrorPtr is the only way to create an ErrorPtr.
66: func NewErrorPtr[A any, T PtrRichError[A]](ptr2 **A) ErrorPtr[A, T] {
67: 	if ptr2 == nil {
68: 		panic("Expected non-nil pointer to some error type")
69: 	}
70: 	return ErrorPtr[A, T]{ptr2: ptr2}
71: }
72: 
73: func (p ErrorPtr[A, T]) Unpack() RichErrorData {
74: 	var empty RichErrorData
75: 	if p.ptr2 == nil {
76: 		panic("Incorrectly created ErrorPtr without going through NewErrorPtr")
77: 	}
78: 	ptr := *p.ptr2
79: 	if ptr == nil {
80: 		return RichErrorData{Err: nil, Attrs: nil}
81: 	}
82: 	// We need this dynamic type checks here because Go doesn't allow
83: 	// constraints on type parameters in methods, and we want to
84: 	// have a method so that we can satisfy the RichError interface.
85: 	val, ok := any(ptr).(RichError)
86: 	if !ok {
87: 		// We need two different type checks here because RichError may be
88: 		// implemented with a struct receiver or a pointer receiver.
89: 		// See the tests for more details.
90: 		if val, ok = any(*ptr).(RichError); !ok {
91: 			panic("Dynamic type check for pointer type failed; did you create ErrorPtr without using NewErrorPtr?")
92: 		}
93: 	}
94: 	if val == nil {
95: 		return empty
96: 	}
97: 	if inner := reflect.ValueOf(val); inner.Kind() == reflect.Pointer && inner.IsNil() {
98: 		return empty
99: 	}
100: 	return val.Unpack()
101: }
102: 
103: // ErasedErrorPtr stores a type-erased 'error' instead of
104: // generic **T like ErrorPtr.
105: type ErasedErrorPtr struct {
106: 	Err *error
107: }
108: 
109: var _ RichError = ErasedErrorPtr{}
110: 
111: func (e ErasedErrorPtr) Unpack() RichErrorData {
112: 	if e.Err == nil || *e.Err == nil {
113: 		return RichErrorData{Err: nil, Attrs: nil}
114: 	}
115: 	if re := RichError(nil); AsInterface(*e.Err, &re) {
116: 		return re.Unpack()
117: 	}
118: 	return RichErrorData{Err: *e.Err, Attrs: nil}
119: }
120: 
121: // Collector represents multiple errors and additional log fields that arose from those errors.
122: // This type is thread-safe.
123: type Collector struct {
124: 	mu         sync.Mutex
125: 	errs       error
126: 	extraAttrs []attribute.KeyValue
127: }
128: 
129: var _ RichError = (*Collector)(nil)
130: 
131: func NewErrorCollector() *Collector { return &Collector{errs: nil} }
132: 
133: func (e *Collector) Collect(err *error, attrs ...attribute.KeyValue) {
134: 	e.mu.Lock()
135: 	defer e.mu.Unlock()
136: 
137: 	if err != nil && *err != nil {
138: 		e.errs = Append(e.errs, *err)
139: 		e.extraAttrs = append(e.extraAttrs, attrs...)
140: 	}
141: }
142: 
143: func (e *Collector) Error() string {
144: 	e.mu.Lock()
145: 	defer e.mu.Unlock()
146: 
147: 	if e.errs == nil {
148: 		return ""
149: 	}
150: 	return e.errs.Error()
151: }
152: 
153: func (e *Collector) Unwrap() error {
154: 	// Collector wraps collected errors, for compatibility with errors.HasType,
155: 	// errors.Is etc it has to implement Unwrap to return the inner errors the
156: 	// collector stores.
157: 	e.mu.Lock()
158: 	defer e.mu.Unlock()
159: 
160: 	return e.errs
161: }
162: 
163: func (e *Collector) Unpack() RichErrorData {
164: 	if e.Error() == "" {
165: 		return RichErrorData{Err: nil, Attrs: nil}
166: 	}
167: 	e.mu.Lock()
168: 	defer e.mu.Unlock()
169: 	// Explicitly clone slice for 1 level of thread safety.
170: 	return RichErrorData{Err: e.errs, Attrs: slices.Clone(e.extraAttrs)}
171: }
