8: 
9: type TreeNode struct {
10: 	TypeName string
11: 	Children []*TreeNode
12: }
13: 
14: func (n *TreeNode) String() string {
15: 	return debugTreeRecursive(n).String()
16: }
17: 
18: func debugTreeRecursive(n *TreeNode) treeprint.Tree {
19: 	if n == nil {
20: 		return treeprint.NewWithRoot("<nil>")
21: 	}
22: 	t := treeprint.NewWithRoot(n.TypeName)
23: 	for _, child := range n.Children {
24: 		t.AddNode(debugTreeRecursive(child))
25: 	}
26: 	return t
27: }
28: 
29: // UnpackTree returns a tree of error types and their children.
30: //
31: // This function is meant for debugging issues when you're trying to write
32: // a test for error handling, and want to inspect the structure of an error
33: // tree.
34: //
35: // DO NOT use this function for matching errors -- use errors.Is, errors.As etc.
36: func UnpackTree(err error) *TreeNode {
37: 	if err == nil {
38: 		return nil
39: 	}
40: 	typeName := reflect.TypeOf(err).String()
41: 	children := []*TreeNode{}
42: 	if e, ok := err.(interface{ Unwrap() []error }); ok {
43: 		for _, suberr := range e.Unwrap() {
44: 			children = append(children, UnpackTree(suberr))
45: 		}
46: 	} else if e, ok := err.(MultiError); ok {
47: 		for _, suberr := range e.Errors() {
48: 			children = append(children, UnpackTree(suberr))
49: 		}
50: 	} else if e, ok := err.(Wrapper); ok {
51: 		children = append(children, UnpackTree(e.Unwrap()))
52: 	} else if e, ok := err.(interface{ Cause() error }); ok {
53: 		children = append(children, UnpackTree(e.Cause()))
54: 	}
55: 	return &TreeNode{typeName, children}
56: }
