{"content":"1: // Copied from https://sourcegraph.com/github.com/ricochet2200/go-disk-usage
2: package diskusage
3: 
4: import "syscall"
5: 
6: type DiskUsage interface {
7: 	Free() uint64
8: 	Size() uint64
9: 	PercentUsed() float32
10: 	Available() uint64
11: }
12: 
13: // DiskUsage contains usage data and provides user-friendly access methods
14: type diskUsage struct {
15: 	stat *syscall.Statfs_t
16: }
17: 
18: // New returns an object holding the disk usage of volumePath
19: // or nil in case of error (invalid path, etc)
20: func New(volumePath string) (DiskUsage, error) {
21: 	var stat syscall.Statfs_t
22: 	if err := syscall.Statfs(volumePath, &stat); err != nil {
23: 		return nil, err
24: 	}
25: 	return &diskUsage{stat: &stat}, nil
26: }
27: 
28: // Free returns total free bytes on file system
29: func (du *diskUsage) Free() uint64 {
30: 	return du.stat.Bfree * uint64(du.stat.Bsize)
31: }
32: 
33: // Size returns total size of the file system
34: func (du *diskUsage) Size() uint64 {
35: 	return uint64(du.stat.Blocks) * uint64(du.stat.Bsize)
36: }
37: 
38: // Used returns total bytes used in file system
39: func (du *diskUsage) used() uint64 {
40: 	return du.Size() - du.Free()
41: }
42: 
43: func (du *diskUsage) usage() float32 {
44: 	return float32(du.used()) / float32(du.Size())
45: }
46: 
47: // PercentUsed returns percentage of use on the file system
48: func (du *diskUsage) PercentUsed() float32 {
49: 	return du.usage() * 100
50: }
51: 
52: // Available return total available bytes on file system to an unprivileged user
53: func (du *diskUsage) Available() uint64 {
54: 	return du.stat.Bavail * uint64(du.stat.Bsize)
55: }
