{"content":"1: package core
2: 
3: // Option represents an optional value.
4: //
5: // Prefer using Option over pointers for struct fields, and over (T, bool)
6: // or pointers for optional return values. This helps avoid heap allocations.
7: //
8: // The zero value of Option is None.
9: type Option[A any] struct {
10: 	value   A
11: 	present bool
12: 	// Uses an extra boolean instead of a pointer representation to reduce
13: 	// the risk of heap allocations for performance-sensitive code.
14: }
15: 
16: // NewOption enables bridging a (T, bool) value to an Option.
17: //
18: // Go allows direct forwarding of two return values into two parameters.
19: // So instead of writing:
20: //
21: //	value, ok := thirdpartylib.SomeFunc()
22: //	optValue := core.NewOption(value, ok)
23: //
24: // You can write:
25: //
26: //	optValue := core.NewOption(thirdpartylib.SomeFunc())
27: func NewOption[A any](value A, ok bool) Option[A] {
28: 	if ok {
29: 		return Some[A](value)
30: 	}
31: 	return None[A]()
32: }
33: 
34: func Some[A any](value A) Option[A] {
35: 	return Option[A]{
36: 		value:   value,
37: 		present: true,
38: 	}
39: }
40: 
41: func None[A any]() Option[A] {
42: 	var zero A
43: 	return Option[A]{
44: 		value:   zero,
45: 		present: false,
46: 	}
47: }
48: 
49: // Maybe returns a valid Option with value if and only if value is not the zero
50: // value of its type.
51: func Maybe[A comparable](value A) Option[A] {
52: 	var zero A
53: 	if value == zero {
54: 		return None[A]()
55: 	}
56: 	return Some(value)
57: }
58: 
59: func MaybePtr[A any](value *A) Option[A] {
60: 	if value == nil {
61: 		return None[A]()
62: 	}
63: 	return Some(*value)
64: }
65: 
66: func (o Option[A]) Compare(other Option[A], cmp func(A, A) int) int {
67: 	if o.IsNone() {
68: 		if other.IsNone() {
69: 			return 0
70: 		}
71: 		return -1
72: 	}
73: 	if other.IsNone() {
74: 		return 1
75: 	}
76: 	v1 := o.Unwrap()
77: 	v2 := other.Unwrap()
78: 	return cmp(v1, v2)
79: }
80: 
81: // Get returns the value if the Option isSome, otherwise it returns the zero value and false
82: //
83: // A common way of using this is to bind the value in an if condition like so:
84: //
85: //	if val, ok := opt.Get(); ok {
86: //	   // do something with val
87: //	}
88: func (o Option[A]) Get() (A, bool) {
89: 	return o.value, o.present
90: }
91: 
92: func (o Option[A]) Unwrap() A {
93: 	if o.IsSome() {
94: 		return o.value
95: 	}
96: 	panic("called Option.Unwrap on None")
97: }
98: 
99: func (o Option[A]) UnwrapOr(defaultValue A) A {
100: 	if o.IsSome() {
101: 		return o.Unwrap()
102: 	}
103: 	return defaultValue
104: }
105: 
106: func (o Option[A]) UnwrapOrElse(defaultFunc func() A) A {
107: 	if o.IsSome() {
108: 		return o.Unwrap()
109: 	}
110: 	return defaultFunc()
111: }
112: 
113: func (o Option[A]) IsSome() bool {
114: 	return o.present
115: }
116: 
117: func (o Option[A]) IsNone() bool {
118: 	return !o.present
119: }
120: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/lib/core/option.go"}

{"content":"1: package core
2: 
3: import (
4: 	"cmp"
5: )
6: 
7: // Pair represents an ad-hoc pair of values.
8: //
9: // Pair is primarily present for better composition of generic APIs
10: // such as in the iterext package.
11: //
12: // For domain-specific pairs of values, prefer defining one-off structs
13: // with appropriate doc comments instead of reusing Pair.
14: //
15: // For example, if you want to represent a pair of a repository ID and a
16: // commit, then might be important for the reader to know whether the commit
17: // is known to belong to the given repository or not (e.g. within the scope
18: // of a given transaction), which is not conveyed if you use Pair.
19: type Pair[A, B any] struct {
20: 	First  A
21: 	Second B
22: }
23: 
24: // Unpack unpacks a Pair into its constituent parts.
25: func (p Pair[A, B]) Unpack() (A, B) {
26: 	return p.First, p.Second
27: }
28: 
29: // NewPair is a helper function for type inference.
30: func NewPair[A, B any](first A, second B) Pair[A, B] {
31: 	return Pair[A, B]{
32: 		First:  first,
33: 		Second: second,
34: 	}
35: }
36: 
37: func LessPair[A, B cmp.Ordered](p1, p2 Pair[A, B]) bool {
38: 	return ComparePair(p1, p2) == -1
39: }
40: 
41: func ComparePair[A, B cmp.Ordered](p1, p2 Pair[A, B]) int {
42: 	if c := cmp.Compare(p1.First, p2.First); c != 0 {
43: 		return c
44: 	}
45: 	return cmp.Compare(p1.Second, p2.Second)
46: }
47: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/lib/core/pair.go"}

