}

func (p ErrorPtr[A, T]) Unpack() RichErrorData {
	var empty RichErrorData
	if p.ptr2 == nil {
		panic("Incorrectly created ErrorPtr without going through NewErrorPtr")
	}
	ptr := *p.ptr2
	if ptr == nil {
		return RichErrorData{Err: nil, Attrs: nil}
	}
	val, ok := any(ptr).(RichError)
	if !ok {
