package check

import "github.com/google/go-cmp/cmp"

func Diff[X any](expected X, got X, options ...cmp.Option) string {
	return cmp.Diff(expected, got, options...)
}

func MustNoDiff[X any](t T, expected X, got X, what string, options ...cmp.Option) {
	t.Helper()
	if diff := Diff(expected, got, options...); diff != "" {
		t.Fatalf("mismatch in %s: (-want +got):\n%s", what, diff)
