// Copied from https://sourcegraph.com/github.com/ricochet2200/go-disk-usage
package diskusage

import "syscall"

type DiskUsage interface {
	Free() uint64
	Size() uint64
	PercentUsed() float32
	Available() uint64
}

type diskUsage struct {
	stat *syscall.Statfs_t
}

func New(volumePath string) (DiskUsage, error) {
	var stat syscall.Statfs_t
	if err := syscall.Statfs(volumePath, &stat); err != nil {
		return nil, err
	}
	return &diskUsage{stat: &stat}, nil
}

func (du *diskUsage) Free() uint64      { return du.stat.Bfree * uint64(du.stat.Bsize) }
func (du *diskUsage) Size() uint64      { return uint64(du.stat.Blocks) * uint64(du.stat.Bsize) }
func (du *diskUsage) used() uint64      { return du.Size() - du.Free() }
func (du *diskUsage) usage() float32    { return float32(du.used()) / float32(du.Size()) }
func (du *diskUsage) PercentUsed() float32 { return du.usage() * 100 }
func (du *diskUsage) Available() uint64{ return du.stat.Bavail * uint64(du.stat.Bsize) }
GOEOF

