package goapi

import (
	"encoding/json"

	"github.com/sourcegraph/sourcegraph/lib/errors"
)

type ContentBlock interface {
	isContentBlock()
}

func (*SourceReferenceContent) isContentBlock() {}
func (*ImageContent) isContentBlock()           {}
func (*SlackThreadContent) isContentBlock()     {}
func (*ForkOrigin) isContentBlock()             {}

type SourceReferenceContent struct {
	Type      string `json:"type"`
	Repo      string `json:"repo"`
	Path      string `json:"path,omitempty"`
	Rev       string `json:"rev,omitempty"`
	LineStart int32  `json:"line_start,omitempty"`
	LineEnd   int32  `json:"line_end,omitempty"`
	Source    string `json:"source,omitempty"`
}

// ImageContent represents an image content block for DeepSearch.
type ImageContent struct {
	Type string `json:"type"`
	Url  string `json:"url"`
}

// SlackThreadContent represents Slack thread context for DeepSearch.
type SlackThreadContent struct {
	Type    string `json:"type"`
	Content string `json:"content"`
}

// ForkOrigin represents a reference to a previous DeepSearch conversation.
type ForkOrigin struct {
	Type       string  `json:"type"`
	QuestionID int32   `json:"question_id"`
	Content    *string `json:"content,omitempty"`
}

// ContentBlocks is a slice of ContentBlock used for JSON marshaling/unmarshaling.
type ContentBlocks []ContentBlock

func (c *ContentBlocks) UnmarshalJSON(data []byte) error {
	if len(data) == 0 || string(data) == "null" {
		*c = nil
		return nil
	}

	var rawBlocks []json.RawMessage
	if err := json.Unmarshal(data, &rawBlocks); err != nil {
		return err
	}

	result := make(ContentBlocks, 0, len(rawBlocks))
	for _, raw := range rawBlocks {
		var discriminator struct {
			Type string `json:"type"`
		}
		if err := json.Unmarshal(raw, &discriminator); err != nil {
			return err
		}

		var block ContentBlock
		switch discriminator.Type {
		case "source_reference":
			var v SourceReferenceContent
			if err := json.Unmarshal(raw, &v); err != nil {
				return err
			}
			block = &v
		case "image":
			var v ImageContent
			if err := json.Unmarshal(raw, &v); err != nil {
				return err
			}
			block = &v
		case "slack_thread":
			var v SlackThreadContent
			if err := json.Unmarshal(raw, &v); err != nil {
				return err
			}
			block = &v
		case "fork_origin":
			var v ForkOrigin
			if err := json.Unmarshal(raw, &v); err != nil {
				return err
			}
			block = &v
		default:
			return errors.Newf("unknown content block type: %q", discriminator.Type)
		}
		result = append(result, block)
	}

	*c = result
	return nil
}

func (c *ContentBlocks) MarshalJSON() ([]byte, error) {
	if c == nil || *c == nil {
		return []byte("null"), nil
	}
	return json.Marshal([]ContentBlock(*c))
}
GOEOF

